import java.io.*;import java.util.*;class Main{static final class RangeModule{List<int[]> intervals=new ArrayList<>();void addRange(int left,int right){List<int[]> merged=new ArrayList<>();int i=0;while(i<intervals.size()&&intervals.get(i)[1]<left)merged.add(intervals.get(i++));int newL=left,newR=right;while(i<intervals.size()&&intervals.get(i)[0]<=newR){newL=Math.min(newL,intervals.get(i)[0]);newR=Math.max(newR,intervals.get(i)[1]);i++;}merged.add(new int[]{newL,newR});while(i<intervals.size())merged.add(intervals.get(i++));intervals=merged;}boolean queryRange(int left,int right){int lo=0,hi=intervals.size()-1;while(lo<=hi){int mid=(lo+hi)/2;int[] cur=intervals.get(mid);if(cur[0]<=left){if(right<=cur[1])return true;lo=mid+1;}else hi=mid-1;}return false;}void removeRange(int left,int right){List<int[]> kept=new ArrayList<>();for(int[] cur:intervals){if(cur[1]<=left||right<=cur[0])kept.add(cur);else{if(cur[0]<left)kept.add(new int[]{cur[0],left});if(right<cur[1])kept.add(new int[]{right,cur[1]});}}intervals=kept;}}public static void main(String[]a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder all=new StringBuilder();for(int tc=0;tc<t;tc++){int ops=Integer.parseInt(d[idx++]);RangeModule rm=new RangeModule();List<String> out=new ArrayList<>();for(int i=0;i<ops;i++){String op=d[idx++];if(op.equals("C")){rm=new RangeModule();out.add("null");}else if(op.equals("A")){int l=Integer.parseInt(d[idx++]),r=Integer.parseInt(d[idx++]);rm.addRange(l,r);out.add("null");}else if(op.equals("R")){int l=Integer.parseInt(d[idx++]),r=Integer.parseInt(d[idx++]);rm.removeRange(l,r);out.add("null");}else{int l=Integer.parseInt(d[idx++]),r=Integer.parseInt(d[idx++]);out.add(rm.queryRange(l,r)?"true":"false");}}if(tc>0)all.append("\n\n");all.append("[").append(String.join(",",out)).append("]");}System.out.print(all);}}
